css_template:
#{{ID}} .news-container-v8 {
position: absolute;
bottom: 0;
left: 0;
width: var(--v-width, 100%);
min-height: var(--v-height, 60px);
background: {{PRIMARY_BG}};
color: {{TITLE_COLOR}};
display: flex;
align-items: center;
overflow: hidden;
border: {{BORDER_WIDTH}}px solid {{BORDER_COLOR}};
border-radius: {{BORDER_RADIUS}}px;
box-sizing: border-box;
font-family: '{{FONT_FAMILY}}', sans-serif;
opacity: 0;
transform: translateY(100px);
box-shadow: {{BOX_SHADOW}};
}
#{{ID}} .news-text-v8 {
position: absolute;
width: auto;
left: 0;
white-space: nowrap;
text-align: left;
font-size: {{TITLE_SIZE}}px;
font-weight: {{TITLE_WEIGHT}};
text-transform: {{TITLE_TRANSFORM}};
padding-left: var(--wiper-width, 170px);
padding-right: 20px;
padding-top: {{PADDING_Y}}px;
padding-bottom: {{PADDING_Y}}px;
box-sizing: border-box;
z-index: 1;
transition: opacity 0.4s ease-in-out;
opacity: 0;
}
#{{ID}} .news-text-v8.visible {
opacity: 1;
}
#{{ID}} .wiper-v8 {
position: absolute;
left: 0;
width: auto;
min-width: 150px;
padding: 0 40px;
height: 100%;
background: {{WIPER_BG}};
display: flex;
align-items: center;
justify-content: center;
box-shadow: 5px 0 15px rgba(0,0,0,0.5);
border-radius: {{BORDER_RADIUS}}px;
z-index: 2;
box-sizing: border-box;
overflow: hidden;
}
#{{ID}} .wiper-v8::before {
content: '';
position: absolute;
top: 0;
left: -100%;
width: 60%;
height: 100%;
display: {{#if WIPER_GLEAM_ENABLED}}block{{else}}none{{/if}};
background: {{WIPER_GLEAM_BG}};
transform: skewX(-20deg);
pointer-events: none;
animation: sweep-gleam-v8 {{WIPER_GLEAM_DURATION}}s infinite ease-in-out;
}
#{{ID}} .wiper-text-v8 {
font-weight: {{WIPER_FONT_WEIGHT}};
font-size: {{WIPER_FONT_SIZE}}px;
font-family: {{WIPER_FONT}}, sans-serif;
color: {{WIPER_TEXT_COLOR}};
letter-spacing: {{WIPER_LETTER_SPACING}}px;
position: relative;
z-index: 1;
white-space: nowrap;
}
#{{ID}} .wiper-v8.move-right {
animation: slide-right-v8 1s linear forwards;
}
#{{ID}} .wiper-v8.snap-back {
animation: slide-back-v8 0.5s ease-in-out forwards;
}
@keyframes slide-right-v8 {
0% { left: 0%; }
100% { left: calc(var(--v-width, 100%) - var(--wiper-width, 150px)); }
}
@keyframes slide-back-v8 {
0% { left: calc(var(--v-width, 100%) - var(--wiper-width, 150px)); }
100% { left: 0%; }
}
@keyframes sweep-gleam-v8 {
0% { left: -100%; }
100% { left: 200%; }
}

js_template:
(() => {
    const root = document.getElementById("{{ID}}");
    const container = root.querySelector('.news-container-v8');
    const textElement = root.querySelector('.news-text-v8');
    const wiper = root.querySelector('.wiper-v8');
    const wiperTextEl = root.querySelector('.wiper-text-v8');
    const gleamEl = root.querySelector('.wiper-v8-gleam');
    const dataEl = root.querySelector('#f-news-list');
    if(!textElement || !container || !wiper || !dataEl) return;

    const DEFAULT_WIPER = "{{WIPER_TEXT}}";
    const WIPER_SHOW = "{{WIPER_SHOW}}" !== "false";

    let newsList = [];
    const b64 = dataEl.getAttribute('data-b64');
    if (b64) {
        try { newsList = JSON.parse(decodeURIComponent(escape(atob(b64 + "=".repeat((4 - b64.length % 4) % 4))))); } catch(e) { try { newsList = JSON.parse(dataEl.innerHTML || "[]"); } catch(err) {} }
    } else {
        try { newsList = JSON.parse(dataEl.innerHTML || "[]"); } catch(e) {}
    }
    if(newsList.length === 0) newsList = ["BRAK WIADOMOŚCI"];

    let currentIndex = 0;
    let activeTimeouts = [];
    let cycleRunning = false;

    function adjustFontSize() {
        const baseFontSizeStr = "{{TITLE_SIZE}}";
        const baseFontSize = parseFloat(baseFontSizeStr) || 40;
        const wiperEl = root.querySelector('.wiper-v8');
        const wiperWidth = (wiperEl && wiperEl.style.display !== 'none') ? wiperEl.offsetWidth : 0;
        if (wiperEl) {
            container.style.setProperty('--wiper-width', (wiperWidth || 20) + 'px');
        }
        const leftPadding = wiperWidth > 0 ? (wiperWidth + 20) : 20;
        const maxWidth = container.offsetWidth - (leftPadding + 20);

        textElement.style.paddingLeft = leftPadding + 'px';
        textElement.style.fontSize = baseFontSize + "px";

        let currentWidth = textElement.scrollWidth - leftPadding;
        if (currentWidth > maxWidth && currentWidth > 0) {
            const newSize = (maxWidth / currentWidth) * baseFontSize;
            textElement.style.fontSize = Math.min(newSize, baseFontSize) + "px";
        }
    }

    function runGleam() {
        if (!cycleRunning || !{{WIPER_GLEAM_ENABLED}}) return;
        if (!gleamEl) return;

        gsap.fromTo(gleamEl, 
            { left: '-150%' }, 
            { 
                left: '150%', 
                duration: {{WIPER_GLEAM_DURATION}} || 2, 
                ease: "power1.inOut",
                onComplete: () => {
                    activeTimeouts.push(setTimeout(runGleam, {{WIPER_GLEAM_FREQUENCY}} * 1000));
                }
            }
        );
    }

    function runCycle() {
        if (!cycleRunning) return;
        textElement.classList.remove('visible');
        const currentMsg = newsList[currentIndex];
        const text = typeof currentMsg === 'object' ? (currentMsg.text || "") : currentMsg;
        const category = typeof currentMsg === 'object' ? (currentMsg.category || "") : "";

        textElement.innerText = text;

        const labelText = category || DEFAULT_WIPER;
        if (wiper) {
             const showWiper = WIPER_SHOW && !!(labelText && labelText.trim());
             wiper.style.display = showWiper ? 'flex' : 'none';
             if (wiperTextEl) wiperTextEl.innerText = labelText;
        }

        adjustFontSize();

        activeTimeouts.push(setTimeout(() => {
            if(!cycleRunning) return;
            textElement.classList.add('visible');
        }, 100));

        activeTimeouts.push(setTimeout(() => {
            if(!cycleRunning) return;
            textElement.classList.remove('visible');
            activeTimeouts.push(setTimeout(() => {
                if(!cycleRunning) return;
                if(wiper && wiper.style.display !== 'none') wiper.className = 'wiper-v8 move-right';
                activeTimeouts.push(setTimeout(() => {
                    if(!cycleRunning) return;
                    if(wiper && wiper.style.display !== 'none') wiper.className = 'wiper-v8 snap-back';
                    activeTimeouts.push(setTimeout(() => {
                        if(!cycleRunning) return;
                        currentIndex = (currentIndex + 1) % newsList.length;
                        runCycle();
                    }, 500));
                }, 1000));
            }, 400));
        }, 4000));
    }

    root.__slt_show = () => {
        cycleRunning = true;
        const tl = gsap.timeline();
        tl.to(container, { opacity: 1, y: 0, duration: 0.6, ease: "power2.out" });
        tl.add(() => {
            runCycle();
            runGleam();
        }, "+ =0.1");
        return tl;
    };

    root.__slt_hide = () => {
        cycleRunning = false;
        activeTimeouts.forEach(t => clearTimeout(t));
        activeTimeouts = [];
        if(window.gsap && gleamEl) gsap.killTweensOf(gleamEl);
        const tl = gsap.timeline();
        tl.to(container, { opacity: 0, y: 100, duration: 0.4, ease: "power2.in" });
        return tl;
    };

    window.addEventListener('resize', adjustFontSize);
})();
